1	export interface Customer {
2	  yearsWithMHPCO: number;
3	  previousContracts?: number;
4	}
5	
6	export interface Item {
7	  type: string;
8	  material?: string;
9	  enchantment?: number;
10	  cursed?: boolean;
11	}
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const COMPONENT_TYPES = ["rune", "moonstone"];
26	const COMPONENTS_PER_BLOCK = 3;
27	const COMPONENT_BLOCK_BASE = 60;
28	const CURSE_SURCHARGE_RATE = 0.5;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	const LOYALTY_YEARS_THRESHOLD = 2;
32	const LOYALTY_DISCOUNT_RATE = 0.2;
33	const FOLLOW_UP_CONTRACTS_THRESHOLD = 1;
34	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
35	
36	export interface Policy {
37	  items: Item[];
38	  remainingCap?: number;
39	}
40	
41	export interface Damage {
42	  itemType: string;
43	  amount: number;
44	}
45	
46	export interface Incident {
47	  damages: Damage[];
48	}
49	
50	export interface ClaimResult {
51	  payout: number;
52	  remainingCap: number;
53	}
54	
55	const INSURANCE_VALUES: Record<string, number> = {
56	  sword: 1000,
57	  amulet: 600,
58	  staff: 800,
59	  potion: 400,
60	  rune: 250,
61	  moonstone: 250,
62	};
63	const DEDUCTIBLE = 100;
64	const CAP_MULTIPLIER = 2;
65	
66	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
67	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
68	
69	function reimbursableAmount(item: Item | undefined, damageAmount: number): number {
70	  const isHighEnchantment = (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
71	  return isHighEnchantment ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE : damageAmount;
72	}
73	
74	const afterDeductible = (amount: number): number => Math.max(0, amount - DEDUCTIBLE);
75	
76	export function claim(policy: Policy, incident: Incident): ClaimResult {
77	  const insuranceSum = policy.items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
78	  const availableCap = policy.remainingCap ?? CAP_MULTIPLIER * insuranceSum;
79	  const rawPayout = incident.damages.reduce((sum, damage) => {
80	    const item = policy.items.find((policyItem) => policyItem.type === damage.itemType);
81	    return sum + afterDeductible(reimbursableAmount(item, damage.amount));
82	  }, 0);
83	  const payout = Math.floor(Math.min(rawPayout, availableCap));
84	  return { payout, remainingCap: availableCap - payout };
85	}
86	
87	export function quote(customer: Customer, items: Item[]): number {
88	  const percentageSurcharge = (rate: number, applies: (item: Item) => boolean): number =>
89	    items.filter(applies).reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rate, 0);
90	
91	  const baseSum = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
92	  // A block of exactly COMPONENTS_PER_BLOCK alike components (same type) replaces their summed base with COMPONENT_BLOCK_BASE.
93	  const blockAdjustment = COMPONENT_TYPES.reduce((adjustment, componentType) => {
94	    const count = items.filter((item) => item.type === componentType).length;
95	    const replacement = COMPONENT_BLOCK_BASE - COMPONENTS_PER_BLOCK * BASE_PREMIUMS[componentType];
96	    return count === COMPONENTS_PER_BLOCK ? adjustment + replacement : adjustment;
97	  }, 0);
98	  const curseSurcharge = percentageSurcharge(CURSE_SURCHARGE_RATE, (item) => item.cursed === true);
99	  const highEnchantmentSurcharge = percentageSurcharge(
100	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
101	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
102	  );
103	  const adjustedBase = baseSum + blockAdjustment;
104	  const proportionalDiscount = (rate: number, qualifies: boolean): number => (qualifies ? adjustedBase * rate : 0);
105	  const firstInsurance = adjustedBase * FIRST_INSURANCE_RATE;
106	  const loyaltyDiscount = proportionalDiscount(LOYALTY_DISCOUNT_RATE, customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD);
107	  const followUpDiscount = proportionalDiscount(FOLLOW_UP_DISCOUNT_RATE, (customer.previousContracts ?? 0) >= FOLLOW_UP_CONTRACTS_THRESHOLD);
108	  return Math.ceil(adjustedBase + curseSurcharge + highEnchantmentSurcharge + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
109	}
